import React, { useContext } from "react";
import { AppContext } from "./AppContext";

const formatBytes = (bytes) => {
  if (bytes === 0) return "0 Bytes";
  const k = 1024;
  const sizes = ["Bytes", "KB", "MB", "GB"];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + " " + sizes[i];
};

export default function Attachment({ attachment, onDownload, status, downloadMessage }) {
  const { colors, caseId, item } = useContext(AppContext);

  return (
    <li
      key={attachment.id}
      style={{
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
        padding: "8px 12px",
        marginBottom: "8px",
        borderRadius: "4px",
        backgroundColor: colors.listBg,
        border: `1px solid ${colors.listBorder}`,
        fontSize: "13px",
      }}
    >
      <div style={{ flex: 1, marginRight: "10px", overflow: "hidden" }}>
        <div
          style={{
            fontSize: "13px",
            fontWeight: "600",
            whiteSpace: "nowrap",
            overflow: "hidden",
            textOverflow: "ellipsis",
            color: colors.textColor,
          }}
        >
          {attachment.name}
        </div>
        <div style={{ fontSize: "11px", color: colors.labelColor }}>
          {downloadMessage || formatBytes(attachment.size)}
        </div>
      </div>
      <button
        disabled={status === "downloading"}
        onClick={onDownload}
        style={{
          padding: "5px 10px",
          borderRadius: "4px",
          border: "1px solid " + colors.primaryColor,
          backgroundColor: status === "downloading" ? colors.primaryColorHover : "transparent",
          color: status === "downloading" ? "#fff" : colors.primaryColor,
          cursor: status === "downloading" ? "progress" : "pointer",
          fontSize: "12px",
          transition: "background-color 0.2s ease",
        }}
        onMouseOver={(e) => {
          if (status !== "downloading") {
            e.target.style.backgroundColor = colors.primaryColor;
            e.target.style.color = "#fff";
          }
        }}
        onMouseOut={(e) => {
          if (status !== "downloading") {
            e.target.style.backgroundColor = "transparent";
            e.target.style.color = colors.primaryColor;
          }
        }}
      >
        {status === "downloading" ? "Saving..." : status === "success" ? "Saved" : "Save"}
      </button>
    </li>
  );
}
