import React, { useEffect } from "react";
import { AppContext } from "./AppContext";
import Attachment from "./Attachment";

export default function AttachmentsList() {
  const { colors, caseId, attachments } = React.useContext(AppContext);
  const [batchDownloadResult, setBatchDownloadResult] = React.useState("");
  const [isDownloadingAll, setIsDownloadingAll] = React.useState(false);
  const [downloadStates, setDownloadStates] = React.useState({}); // To track download status per attachment

  useEffect(() => {
    const initialStates = {};
    attachments.forEach((att) => {
      initialStates[att.id] = { status: "idle", downloadMessage: "" };
    });
    setDownloadStates(initialStates);
  }, [Office.context.mailbox.item, attachments]);

  if (!attachments || attachments.length === 0) {
    return <div></div>;
  }

  const downloadAttachment = async (attachmentId) => {
    try {
      const currentItem = Office.context.mailbox.item;
      if (!currentItem) {
        return false;
      }
      if (!caseId) {
        setDownloadStates((prevStates) => ({
          ...prevStates,
          [attachmentId]: { status: "error", downloadMessage: "❌ Please fill in the CaseID." },
        }));
        return false;
      }
      setDownloadStates((prevStates) => ({
        ...prevStates,
        [attachmentId]: { status: "downloading", downloadMessage: "Saving..." },
      }));

      const messageId = currentItem.itemId;
      const emailAddress = Office.context.mailbox.userProfile.emailAddress;
      const payload = {
        Email: emailAddress,
        MessageID: messageId,
        CaseID: caseId,
        AttachmentID: attachmentId,
      };

      const response = await fetch("https://outlook-rbs.it-bed.workers.dev/downloadAttachment", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload),
      });

      if (response.ok) {
        const data = await response.json();
        const text = JSON.parse(data.text);

        if ("Error" in text) {
          setDownloadStates((prevStates) => ({
            ...prevStates,
            [attachmentId]: { status: "error", downloadMessage: `❌ ${text.Error}` },
          }));
          return false;
        }
        if ("error" in text) {
          setDownloadStates((prevStates) => ({
            ...prevStates,
            [attachmentId]: { status: "error", downloadMessage: `❌ ${text.error.message}` },
          }));
          return false;
        }
        setDownloadStates((prevStates) => ({
          ...prevStates,
          [attachmentId]: { status: "success", downloadMessage: "✅ Saved" },
        }));
        return true;
      } else {
        const text = await response.text();
        setDownloadStates((prevStates) => ({
          ...prevStates,
          [attachmentId]: { status: "error", downloadMessage: `❌ ${text}` },
        }));
        return false;
      }
    } catch (error) {
      setDownloadStates((prevStates) => ({
        ...prevStates,
        [attachmentId]: { status: "error", downloadMessage: `❌ ${error.message}` },
      }));
      return false;
    }
  };

  const downloadAllAttachments = async () => {
    try {
      const currentItem = Office.context.mailbox.item;
       if (!currentItem) {
        return;
      }
      if (!currentItem) {
        return;
      }
      if (!caseId) {
        setBatchDownloadResult("❌ Please fill in the CaseID.");
        return;
      }
      setIsDownloadingAll(true);
      setBatchDownloadResult("Initializing...");
      let successCount = 0;
      for (const attachment of attachments) {
        // Trigger download for each attachment
        const success = await downloadAttachment(attachment.id);
        if (success) {
          successCount++;
        }
      }
      setIsDownloadingAll(false);
      if (successCount === attachments.length) {
        setBatchDownloadResult(`✅ All files saved.`);
      } else {
        setBatchDownloadResult(`⚠️ ${successCount}/${attachments.length} files saved.`);
      }
    } catch (error) {
      console.log("❌ Error: " + error.message);
    }
  };

  return (
    <div style={{ borderTop: `1px solid ${colors.listBorder}`, paddingTop: "20px" }}>
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          marginBottom: "15px",
        }}
      >
        <div style={{ display: "flex", alignItems: "baseline", gap: "8px" }}>
          <h4 style={{ margin: 0, fontSize: "16px", color: colors.textColor }}>
            Attachments ({attachments.length})
          </h4>
          <span
            style={{
              fontSize: "11px",
              color:
                batchDownloadResult.includes("❌") || batchDownloadResult.includes("⚠️")
                  ? colors.resultErrorColor
                  : colors.resultSuccessColor,
            }}
          >
            {batchDownloadResult}
          </span>
        </div>

        <button
          disabled={isDownloadingAll || attachments.length === 0}
          onClick={downloadAllAttachments}
          style={{
            padding: "6px 14px",
            borderRadius: "4px",
            border: "none",
            backgroundColor: colors.primaryColor,
            color: "#fff",
            fontWeight: "600",
            fontSize: "12px",
            cursor: attachments.length === 0 ? "not-allowed" : "pointer",
            transition: "all 0.2s ease",
            display: "flex",
            alignItems: "center",
          }}
          onMouseOver={(e) => (e.target.style.backgroundColor = colors.primaryColorHover)}
          onMouseOut={(e) => (e.target.style.backgroundColor = colors.primaryColor)}
        >
          {isDownloadingAll ? "Saving..." : "Save All"}
        </button>
      </div>

      <ul style={{ listStyle: "none", padding: 0, margin: 0 }}>
        {attachments.map((attachment) => (
          <Attachment
            key={attachment.id}
            attachment={attachment}
            onDownload={() => downloadAttachment(attachment.id)}
            status={downloadStates[attachment.id]?.status}
            downloadMessage={downloadStates[attachment.id]?.downloadMessage}
          />
        ))}
      </ul>
    </div>
  );
}
